#' counts$set(c(5L, 7L, 0L, 0L, 0L, 0L))      # tick 0 = (5, 7)
#' carry_forward(counts, 0L)
#' counts$values()[2L, ]                       # 5 7  (carried to tick 1)
#' @export
carry_forward <- function(counter, tick) .Call(wrap__carry_forward, counter, tick)

#' Count occurrences of each value, NumPy `bincount`-style, into a buffer.
#'
#' For each bin `b` in `0..nbins`, computes how many elements of `values` equal
#' `b` and writes that into `counts[b]`. `values` must be an integer-typed
#' [Column] whose elements lie in `0..nbins` (they are used as bin indices);
#' `counts` is a numeric [Column] and the result is written into **slice `slot`**
#' of it â€” the `nbins` entries `slot*slice_len .. slot*slice_len + nbins` â€”
#' overwriting them while leaving the rest of the slice (and other slices)
#' untouched. For a scalar `counts` (shape `(1, n)`) the only slice is `slot = 0`,
#' the whole vector; for a 2-D report (e.g. `(n_ticks, n_nodes)`) `slot` selects a
#' tick's row. The work is parallelized with private per-thread histograms, so
#' there are no write collisions.
#'
#' @param values An integer-typed `Column` of bin indices (`i8`..`u32`).
#' @param nbins  Number of bins; a non-negative integer `<= counts`'s slice length.
#' @param counts A numeric `Column` that receives the counts (modified in place).
#' @param slot   Which slice of `counts` to write; a non-negative integer
#'   `< counts`'s slice count. Defaults to `0` (the whole vector for a scalar
#'   `counts`, or the first tick of a report). `@param` is optional.
#' @return `NULL` (invisibly); the result is written into `counts`.
#' @examples
#' values <- allocate_scalar("u16", 6L)
#' values$set(c(0, 1, 1, 2, 2, 2))
#' counts <- allocate_scalar("i32", 3L)
#' bincount(values, 3L, counts)
#' counts$values()   # 1 2 3
#' @noRd
bincount_impl <- function(values, nbins, counts, slot) .Call(wrap__bincount_impl, values, nbins, counts, slot)

#' Weighted bincount: sum each element's weight into its bin (NumPy
#' `bincount(values, weights=...)`).
#'
#' For each bin `b` in `0..nbins`, computes `sum of weights[i] over all i with
#' values[i] == b` and writes it into **slice `slot`** of `counts` (the entries
#' `slot*slice_len .. slot*slice_len + nbins`), overwriting them. `values` must be
#' an integer-typed [Column] of bin indices in `0..nbins`; `weights` is any numeric
#' [Column] (signed, unsigned, or floating point) the SAME length as `values`;
#' `counts` is a numeric [Column] whose slice length is `>= nbins`. For a scalar
#' `counts` the only slice is `slot = 0` (the whole vector); for a 2-D report
#' `slot` selects a tick's row. Parallelized with private per-thread accumulators,
#' so there are no write collisions.
#'
#' @param values  An integer-typed `Column` of bin indices (`i8`..`u32`).
#' @param weights A numeric `Column` (any type), the same length as `values`.
#' @param nbins   Number of bins; a non-negative integer `<= counts`'s slice length.
#' @param counts  A numeric `Column` that receives the sums (modified in place).
#' @param slot    Which slice of `counts` to write; a non-negative integer
#'   `< counts`'s slice count. Defaults to `0`.
#' @return `NULL` (invisibly); the result is written into `counts`.
#' @examples
#' values  <- allocate_scalar("u16", 5L); values$set(c(0, 0, 1, 2, 2))
#' weights <- allocate_scalar("f64", 5L); weights$set(c(1.5, 2.5, 4, 1, 3))
#' counts  <- allocate_scalar("f64", 3L)
#' bincountw(values, weights, 3L, counts)
#' counts$values()   # 4 4 4
#' @noRd
bincountw_impl <- function(values, weights, nbins, counts, slot) .Call(wrap__bincountw_impl, values, weights, nbins, counts, slot)

#' One SIR recovery step for tick `tick`: recover expired infectious agents.
#'
#' For each of the first `count` agents whose `state` is infectious (`I`),
#' decrements its `u8` `timer`; when the timer reaches zero the agent becomes
#' recovered (`R`). The number of recoveries per node is counted in parallel
#' (private per-thread node buffers, summed at the end) and applied as a delta to
#' column `tick + 1` of the census: `I` down, `R` up; the per-node recovery count is
#' also recorded in column `tick` of the `recoveries` flow report.
#'
#' The census is updated IN PLACE at column `tick + 1`, which the caller must have
#' already seeded by calling [carry_forward()] on each census counter for this tick
#' (S, I, R) â€” `sir_step` itself no longer carries the census forward.
#'
#' `i_count` / `r_count` are `n_ticks+1 Ã— n_nodes` i32 census Columns; `recoveries`
#' is an `n_ticks Ã— n_nodes` i32 flow Column.
#'
#' @param state      Per-agent `u8` state Column (mutated).
#' @param timer      Per-agent `u8` countdown Column (mutated).
#' @param nodeid     Per-agent `u16` 0-based node-id Column.
#' @param count      Number of active agents to process.
#' @param i_count,r_count  `n_ticks+1 Ã— n_nodes` i32 census Columns (mutated at `tick+1`).
#' @param recoveries `n_ticks Ã— n_nodes` i32 flow Column (mutated at `tick`).
#' @param tick       0-based tick index; the recovery delta is applied to column `tick+1`.
#' @return `NULL` (invisibly); the Columns are modified in place.
#' @export
sir_step <- function(state, timer, nodeid, count, i_count, r_count, recoveries, tick) .Call(wrap__sir_step, state, timer, nodeid, count, i_count, r_count, recoveries, tick)

#' Compute the per-node force of infection (FOI) for one tick.
#'
#' Computes the frequency-dependent, network-redistributed FOI **rate** into column
#' `tick` of `foi`. The local rate per node is
#' `r[k] = beta[k] * seasonality[k] * infected[k] / population[k]`, redistributed as
#' `foi[k] = r[k] * (1 - sum_j W[k, j]) + sum_i r[i] * W[i, k]`. `transmission()`
#' turns this rate into a per-tick probability `1 - exp(-foi)`. Call it after
#' `sir_step` and just before `transmission`.
#'
#' Index conventions: `infected` and `population` are census buffers read at the
#' POST-RECOVERY working column `tick + 1` (so agents recovering this tick are
#' excluded, and the denominator is the current population â€” which may change once
#' vital dynamics are added). `beta` and `seasonality` are exogenous modifier grids
#' read at the interval column `tick`. The result is written to `foi[tick]`.
#'
#' @param infected   Infectious-count census Column (`nodes$I`), `slice_len == n_nodes`.
#' @param population Per-node population census Column (`nodes$N`); the FOI denominator.
#' @param beta       Transmission-coefficient grid (`n_ticks x n_nodes`, from
#'   [values_map()]).
#' @param seasonality Seasonal-modifier grid (`n_ticks x n_nodes`, from [values_map()]).
#' @param network    An `n_nodes x n_nodes` numeric coupling matrix.
#' @param foi        A 2-D f64 Column (`(n_ticks-1) x n_nodes`); column `tick` is overwritten.
#' @param tick       0-based tick index: reads `beta[tick]`/`seasonality[tick]` and
#'   `infected[tick+1]`/`population[tick+1]`, writes `foi[tick]`.
#' @return `NULL` (invisibly); the result is written into `foi`.
#' @export
calc_foi <- function(infected, population, beta, seasonality, network, foi, tick) .Call(wrap__calc_foi, infected, population, beta, seasonality, network, foi, tick)

#' Transmission step for tick `tick`: move susceptibles into a receiving state.
#'
#' Converts column `tick` of `foi` (a rate) to a per-node per-tick infection
#' probability `p[k] = 1 - exp(-foi[k])` â€” computed ONCE per node, not per agent.
#' Then, for each of the first `count` susceptible (`S`) agents, with probability
#' `p[nodeid]` it moves the agent into `to_state` â€” `I` for an SIR model or `E` for
#' SEIR â€” drawing the agent's `timer` for that state from `duration` (rounded to
#' whole ticks, clamped to `[1, 255]`) and tallying the event for its node. The
#' timer is whatever clock the receiving state uses next (incubation for `E`,
#' infectious period for `I`); the caller passes the matching `timer` column and
#' `duration`. New infections per node are counted in parallel (private per-thread
#' buffers, summed at the end) and applied as a delta to column `tick + 1` of the
#' census (`S` down, the receiving state's `to_count` up; the caller has already
#' carried the census forward), and recorded in column `tick` of `incidence`.
#'
#' @param state      Per-agent `u8` state Column (mutated).
#' @param timer      Per-agent `u8` countdown Column for the receiving state (mutated).
#' @param nodeid     Per-agent `u16` 0-based node-id Column.
#' @param count      Number of active agents to process.
#' @param foi        `n_ticks x n_nodes` f64 FOI Column (from [calc_foi()]); column
#'   `tick` is read.
#' @param s_count    `n_ticks+1 Ã— n_nodes` i32 census Column for `S` (mutated at `tick+1`).
#' @param to_count   `n_ticks+1 Ã— n_nodes` i32 census Column for the receiving state
#'   `to_state` (mutated at `tick+1`).
#' @param incidence  `n_ticks x n_nodes` i32 flow Column (mutated at `tick`).
#' @param tick       0-based tick index.
#' @param to_state   State code new infections enter (e.g. `laser_states()[["I"]]`
#'   for SIR or `[["E"]]` for SEIR).
#' @param duration   A Distribution from which the receiving state's timer is drawn.
#' @return `NULL` (invisibly); the Columns are modified in place.
#' @export
transmission <- function(state, timer, nodeid, count, foi, s_count, to_count, incidence, tick, to_state, duration) .Call(wrap__transmission, state, timer, nodeid, count, foi, s_count, to_count, incidence, tick, to_state, duration)

#' Fixed-capacity struct-of-arrays population or patch data store.
#'
#' Mirrors `laser.core.LaserFrame` from Python. Each property occupies a
#' pre-allocated backing array; `count` tracks how many entries are active.
#'
#' **Scalar properties** store one value per entry (length = `capacity`).
#'
#' **Vector properties** store `length` values per entry, laid out column-major
#' so that `get_col(name, col)` returns a contiguous memory slice. This is
#' R's native matrix storage order and makes per-tick node-state updates fast.
#'
#' @export
#'
#' @section Methods:
#'\subsection{Method `new`}{
#'Create a new `LaserFrame`.
#'
#' \subsection{Arguments}{
#'\describe{
#'\item{`capacity`}{Maximum number of entries (agents or nodes). Must be positive.}
#'\item{`initial_count`}{Number of entries active at construction. Pass `-1` (the default) to set active count equal to `capacity`.}
#'}}
#' \subsection{return}{
#'A new `LaserFrame` object.
#'}
#' \subsection{export}{
#'
#'}
#'}
#'
#'\subsection{Method `count`}{
#'Number of currently active entries.
#' \subsection{export}{
#'
#'}
#'}
#'
#'\subsection{Method `capacity`}{
#'Total capacity (fixed at construction).
#' \subsection{export}{
#'
#'}
#'}
#'
#'\subsection{Method `scalar_names`}{
#'Names of all scalar properties, sorted alphabetically.
#' \subsection{export}{
#'
#'}
#'}
#'
#'\subsection{Method `vector_names`}{
#'Names of all vector properties, sorted alphabetically.
#' \subsection{export}{
#'
#'}
#'}
#'
#'\subsection{Method `vector_ncols`}{
#'Number of columns in a named vector property.
#'
#' \subsection{Arguments}{
#'\describe{
#'\item{`name`}{Vector property name.}
#'}}
#' \subsection{export}{
#'
#'}
#'}
#'
#'\subsection{Method `describe`}{
#'Human-readable summary of the frame's properties and memory layout.
#' \subsection{export}{
#'
#'}
#'}
#'
#'\subsection{Method `add_scalar_property`}{
#'Add a scalar property (one value per entry).
#'
#' \subsection{Arguments}{
#'\describe{
#'\item{`name`}{Property name. Must not already exist.}
#'\item{`dtype`}{`"integer"`, `"real"`, or `"logical"`.}
#'\item{`default`}{Fill value for the backing array.}
#'}}
#' \subsection{export}{
#'
#'}
#'}
#'
#'\subsection{Method `add_vector_property`}{
#'Add a vector property (`capacity Ã— length`, column-major).
#'
#'The backing array has `capacity * length` elements.
#'Element `[entry, col]` is stored at offset `entry + col * capacity`.
#'Column `col` (all active entries for one time-step) is contiguous.
#'
#' \subsection{Arguments}{
#'\describe{
#'\item{`name`}{Property name. Must not already exist.}
#'\item{`length`}{Number of columns (e.g., `nticks + 1` for a time-series).}
#'\item{`dtype`}{`"integer"`, `"real"`, or `"logical"`.}
#'\item{`default`}{Fill value.}
#'}}
#' \subsection{export}{
#'
#'}
#'}
#'
#'\subsection{Method `add`}{
#'Activate `n` additional entries and return their 1-based index range.
#'
#'Returns `c(start, end)` (both inclusive, 1-based) so that
#'`frame$get("prop")[start:end]` addresses the newly activated entries.
#'
#' \subsection{Arguments}{
#'\describe{
#'\item{`n`}{Number of entries to activate.}
#'}}
#' \subsection{export}{
#'
#'}
#'}
#'
#'\subsection{Method `squash`}{
#'Compact active entries, keeping only those where `mask` is `TRUE`.
#'
#'All scalar and vector properties are squashed in place.
#'`count` is updated to the number of kept entries.
#'
#' \subsection{Arguments}{
#'\describe{
#'\item{`mask`}{Logical vector of length `count`.}
#'}}
#' \subsection{export}{
#'
#'}
#'}
#'
#'\subsection{Method `sort_by`}{
#'Reorder active scalar properties by `perm` (1-based permutation of length `count`).
#'
#'Each property is permuted in parallel across available CPU threads via Rayon.
#'Only scalar properties are reordered; vector properties (time-series) are left unchanged.
#'
#' \subsection{Arguments}{
#'\describe{
#'\item{`perm`}{Integer vector of length `count`. Must be a valid permutation of `1:count`.}
#'}}
#' \subsection{export}{
#'
#'}
#'}
#'
#'\subsection{Method `get`}{
#'Return the active slice of a scalar property as an R vector.
#'
#' \subsection{Arguments}{
#'\describe{
#'\item{`name`}{Scalar property name.}
#'}}
#' \subsection{export}{
#'
#'}
#'}
#'
#'\subsection{Method `set`}{
#'Overwrite the active slice of a scalar property from an R vector.
#'
#'Integer and real vectors are accepted for integer and real properties
#'respectively; integer values are accepted for real properties (coerced).
#'
#' \subsection{Arguments}{
#'\describe{
#'\item{`name`}{Scalar property name.}
#'\item{`values`}{R vector of length `count`.}
#'}}
#' \subsection{export}{
#'
#'}
#'}
#'
#'\subsection{Method `get_col`}{
#'Return one column of a vector property as an R vector.
#'
#'The column is returned for active entries only (length = `count`).
#'Columns are **1-based**: column 1 is the first column.
#'
#' \subsection{Arguments}{
#'\describe{
#'\item{`name`}{Vector property name.}
#'\item{`col`}{Column index (1-based).}
#'}}
#' \subsection{export}{
#'
#'}
#'}
#'
#'\subsection{Method `set_col`}{
#'Overwrite one column of a vector property from an R vector.
#'
#' \subsection{Arguments}{
#'\describe{
#'\item{`name`}{Vector property name.}
#'\item{`col`}{Column index (1-based).}
#'\item{`values`}{R vector of length `count`.}
#'}}
#' \subsection{export}{
#'
#'}
#'}
#'
#'\subsection{Method `get_matrix`}{
#'Return a vector property as an R matrix of shape `(count, ncols)`.
#'
#'Because both R and the backing store use column-major layout, each
#'column of the returned matrix is a direct contiguous copy.
#'
#' \subsection{Arguments}{
#'\describe{
#'\item{`name`}{Vector property name.}
#'}}
#' \subsection{export}{
#'
#'}
#'}
#'
LaserFrame <- new.env(parent = emptyenv())

LaserFrame$new <- function(capacity, initial_count) .Call(wrap__LaserFrame__new, capacity, initial_count)

LaserFrame$count <- function() .Call(wrap__LaserFrame__count, self)

LaserFrame$capacity <- function() .Call(wrap__LaserFrame__capacity, self)

LaserFrame$scalar_names <- function() .Call(wrap__LaserFrame__scalar_names, self)

LaserFrame$vector_names <- function() .Call(wrap__LaserFrame__vector_names, self)

LaserFrame$vector_ncols <- function(name) .Call(wrap__LaserFrame__vector_ncols, self, name)

LaserFrame$describe <- function() .Call(wrap__LaserFrame__describe, self)

LaserFrame$add_scalar_property <- function(name, dtype, default) .Call(wrap__LaserFrame__add_scalar_property, self, name, dtype, default)

LaserFrame$add_vector_property <- function(name, length, dtype, default) .Call(wrap__LaserFrame__add_vector_property, self, name, length, dtype, default)

LaserFrame$add <- function(n) .Call(wrap__LaserFrame__add, self, n)

LaserFrame$squash <- function(mask) .Call(wrap__LaserFrame__squash, self, mask)

LaserFrame$sort_by <- function(perm) .Call(wrap__LaserFrame__sort_by, self, perm)

LaserFrame$get <- function(name) .Call(wrap__LaserFrame__get, self, name)

LaserFrame$set <- function(name, values) .Call(wrap__LaserFrame__set, self, name, values)

LaserFrame$get_col <- function(name, col) .Call(wrap__LaserFrame__get_col, self, name, col)

LaserFrame$set_col <- function(name, col, values) .Call(wrap__LaserFrame__set_col, self, name, col, values)

LaserFrame$get_matrix <- function(name) .Call(wrap__LaserFrame__get_matrix, self, name)

